<template>
  <view class="calendar-picker">
    <view class="cal-header">
      <view class="cal-nav-btn" @tap="prevMonth"><text class="nav-arrow">‹</text></view>
      <view class="cal-month-display" @tap="toggleYearMonth">
        <text class="cal-year-month">{{ yearMonthText }}</text>
        <text class="cal-dropdown-arrow">{{ showDropdown ? '▲' : '▼' }}</text>
      </view>
      <view class="cal-nav-btn" @tap="nextMonth"><text class="nav-arrow">›</text></view>
    </view>
    <view class="cal-dropdown" v-if="showDropdown">
      <view class="dropdown-row">
        <view class="dropdown-item" v-for="m in 12" :key="m" :class="{ active: month === m }" @tap="selectMonth(m)"><text>{{ m }}月</text></view>
      </view>
      <view class="dropdown-row">
        <view class="dropdown-item" v-for="y in yearOptions" :key="y" :class="{ active: year === y }" @tap="selectYear(y)"><text>{{ y }}年</text></view>
      </view>
    </view>
    <view class="cal-weekdays">
      <view class="cal-weekday" v-for="d in weekdays" :key="d"><text>{{ d }}</text></view>
    </view>
    <view class="cal-grid">
      <view class="cal-cell" v-for="cell in calendarCells" :key="cell.key">
        <view class="cal-day" :class="getCellClass(cell)" @tap="onDayTap(cell)">
          <text class="cal-day-num">{{ cell.display }}</text>
          <text class="cal-holiday" v-if="cell.holiday">{{ cell.holiday }}</text>
        </view>
      </view>
    </view>
    <view class="cal-selected" v-if="selectMode === 'range' && selectedRange.start">
      <text class="cal-selected-text">{{ formatDate(selectedRange.start) }} ~ {{ formatDate(selectedRange.end || selectedRange.start) }}</text>
    </view>
  </view>
</template>
<script setup>
import { ref, computed } from 'vue'
const props = defineProps({ selectMode: { type: String, default: 'single' }, selectDate: { type: [String, Object], default: '' }, begin: { type: String, default: '' }, end: { type: String, default: '' }, disabled: { type: Array, default: () => [] } })
const emit = defineEmits(['update:selectDate', 'onChange'])
const year = ref(new Date().getFullYear())
const month = ref(new Date().getMonth() + 1)
const showDropdown = ref(false)
const selectedRange = ref({ start: '', end: '' })
const tempSelection = ref('')
const weekdays = ['日', '一', '二', '三', '四', '五', '六']
const yearOptions = computed(() => { const o = []; for (let y = year.value - 5; y <= year.value + 5; y++) o.push(y); return o })
const yearMonthText = computed(() => year.value + '年' + month.value + '月')
const calendarCells = computed(() => {
  const cells = []
  const firstDay = new Date(year.value, month.value - 1, 1)
  const lastDay = new Date(year.value, month.value, 0)
  const sp = firstDay.getDay()
  const dim = lastDay.getDate()
  for (let i = 0; i < sp; i++) { const pd = new Date(year.value, month.value - 1, -sp + i + 1); cells.push({ key: 'pad-' + i, display: pd.getDate(), date: fmt(pd), isPadding: true }) }
  for (let d = 1; d <= dim; d++) { const dt = new Date(year.value, month.value - 1, d); cells.push({ key: 'day-' + d, display: d, date: fmt(dt), isPadding: false, holiday: getHol(fmt(dt)) }) }
  while (cells.length < 42) { const i = cells.length; const pd = new Date(year.value, month.value, i - dim - sp + 1); cells.push({ key: 'pe-' + i, display: pd.getDate(), date: fmt(pd), isPadding: true }) }
  return cells
})
function fmt(d) { return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0') }
function getHol(ds) { const h = { '01-01': '元旦', '02-10': '春节', '05-01': '劳动', '06-10': '端午', '09-15': '中秋', '10-01': '国庆' }; return h[ds.substring(5)] || '' }
function getCellClass(cell) {
  const c = []
  if (cell.isPadding) c.push('cal-day-padding')
  const today = fmt(new Date())
  if (cell.date === today) c.push('cal-day-today')
  if (props.disabled.indexOf(cell.date) >= 0) c.push('cal-day-disabled')
  if (props.begin && cell.date < props.begin) c.push('cal-day-disabled')
  if (props.end && cell.date > props.end) c.push('cal-day-disabled')
  if (props.selectMode === 'single' && props.selectDate === cell.date) c.push('cal-day-selected')
  if (props.selectMode === 'range') {
    const s = selectedRange.value.start, e = selectedRange.value.end
    if (cell.date === s || cell.date === e) c.push('cal-day-range-start', 'cal-day-range-end')
    if (s && e && cell.date > s && cell.date < e) c.push('cal-day-range-middle')
    if (tempSelection.value && cell.date === tempSelection.value && !s) c.push('cal-day-temp')
  }
  return c.join(' ')
}
function onDayTap(cell) {
  if (cell.isPadding) return
  if (props.disabled.indexOf(cell.date) >= 0) return
  if (props.begin && cell.date < props.begin) return
  if (props.end && cell.date > props.end) return
  if (props.selectMode === 'single') { emit('update:selectDate', cell.date); emit('onChange', cell.date) }
  else if (props.selectMode === 'range') {
    const sr = selectedRange.value
    if (!sr.start || (sr.start && sr.end)) { selectedRange.value = { start: cell.date, end: '' }; tempSelection.value = '' }
    else {
      if (cell.date < sr.start) selectedRange.value = { start: cell.date, end: sr.start }
      else selectedRange.value = { start: sr.start, end: cell.date }
      emit('update:selectDate', { start: selectedRange.value.start, end: selectedRange.value.end })
      emit('onChange', { start: selectedRange.value.start, end: selectedRange.value.end })
      tempSelection.value = ''
    }
  }
}
function prevMonth() { if (month.value === 1) { year.value--; month.value = 12 } else month.value-- }
function nextMonth() { if (month.value === 12) { year.value++; month.value = 1 } else month.value++ }
function toggleYearMonth() { showDropdown.value = !showDropdown.value }
function selectMonth(m) { month.value = m; showDropdown.value = false }
function selectYear(y) { year.value = y; showDropdown.value = false }
function formatDate(ds) { if (!ds) return ''; return ds.substring(5).replace('-', '/') }
if (props.selectMode === 'range' && props.selectDate && typeof props.selectDate === 'object') { selectedRange.value = { start: props.selectDate.start, end: props.selectDate.end } }
defineExpose({ prevMonth, nextMonth })
</script>
<style scoped>
.calendar-picker { background: #fff; border-radius: 24rpx; padding: 24rpx; box-shadow: 0 4rpx 16rpx rgba(0,0,0,0.06); }
.cal-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 20rpx; }
.cal-nav-btn { width: 64rpx; height: 64rpx; display: flex; align-items: center; justify-content: center; border-radius: 50%; background: #F8FAFC; }
.cal-nav-btn:active { background: #E2E8F0; }
.nav-arrow { font-size: 36rpx; color: #6366F1; font-weight: bold; }
.cal-month-display { display: flex; align-items: center; gap: 8rpx; padding: 8rpx 20rpx; background: linear-gradient(135deg, #6366F1 0%, #8B5CF6 100%); border-radius: 40rpx; }
.cal-year-month { font-size: 28rpx; color: #fff; font-weight: 600; }
.cal-dropdown-arrow { font-size: 20rpx; color: rgba(255,255,255,0.8); }
.cal-dropdown { background: #F8FAFC; border-radius: 16rpx; padding: 16rpx; margin-bottom: 16rpx; display: flex; gap: 16rpx; }
.dropdown-row { flex: 1; display: flex; flex-wrap: wrap; gap: 8rpx; }
.dropdown-item { flex: 0 0 calc(25% - 6rpx); text-align: center; padding: 8rpx 0; border-radius: 8rpx; font-size: 22rpx; color: #64748B; }
.dropdown-item.active { background: #6366F1; color: #fff; font-weight: 600; }
.cal-weekdays { display: flex; margin-bottom: 8rpx; }
.cal-weekday { flex: 1; text-align: center; font-size: 22rpx; color: #94A3B8; font-weight: 600; padding: 8rpx 0; }
.cal-grid { display: flex; flex-wrap: wrap; }
.cal-cell { flex: 0 0 calc(100% / 7); padding: 4rpx; }
.cal-day { display: flex; flex-direction: column; align-items: center; justify-content: center; height: 72rpx; border-radius: 50%; font-size: 26rpx; color: #1E293B; position: relative; }
.cal-day-num { font-size: 26rpx; font-weight: 500; line-height: 1; }
.cal-holiday { font-size: 16rpx; color: #EF4444; margin-top: 2rpx; line-height: 1; }
.cal-day-padding { color: #CBD5E1; }
.cal-day-today { background: #EEF2FF; color: #6366F1; font-weight: 700; }
.cal-day-disabled { color: #E2E8F0; pointer-events: none; }
.cal-day-selected { background: linear-gradient(135deg, #6366F1 0%, #8B5CF6 100%) !important; color: #fff !important; font-weight: 700; box-shadow: 0 4rpx 12rpx rgba(99, 102, 241, 0.3); }
.cal-day-range-start, .cal-day-range-end { background: linear-gradient(135deg, #6366F1 0%, #8B5CF6 100%) !important; color: #fff !important; font-weight: 700; border-radius: 50% 0 0 50% !important; box-shadow: 0 4rpx 12rpx rgba(99, 102, 241, 0.3); }
.cal-day-range-start { border-radius: 50% 0 0 50% !important; }
.cal-day-range-end { border-radius: 0 50% 50% 0 !important; }
.cal-day-range-middle { background: #EEF2FF !important; border-radius: 0 !important; }
.cal-day-temp { background: rgba(99, 102, 241, 0.15) !important; border-radius: 0 !important; }
.cal-selected { margin-top: 16rpx; padding: 16rpx; background: #F8FAFC; border-radius: 12rpx; text-align: center; }
.cal-selected-text { font-size: 24rpx; color: #6366F1; font-weight: 500; }
</style>